import React, { Component } from 'react';
import { Table } from 'antd';
import axios from 'axios';
import YHLiveMDApk from './YHLiveMDApk';
import store from '../store/store.js';
import './YHLiveMD.css';
import { Row, Col } from 'antd';
class ListLive extends Component {
  constructor(){
    super();
    this.state={
      msg:"这里是永辉门店",
      shop_value:"田林路",
      datalist:[],
      openApiCode:"OPENAPI_000332",
      yearID:2018,
      monthID:11,
      shop_id:"9D13",
      quzong_name:"上海区",
      maoliShop:"",
      rijunShop:"",
      shunhaoShop:"",
      year_month:"2018-11"
    } 
  }
  // 开始阶段要进行内容绘制
  componentWillMount(){
    this.requistData(this)
  }
  
  requistData(_this){
    axios.get('http://yc-bi-api.yonghuivip.com/portal-api/openApi/portal/report',{
      params:{
        openApiCode:this.state.openApiCode,
        year_id:this.state.yearID,
        month_id:this.state.monthID,
        // year_month:"2018-11"
        // year_month:this.state.year_month
        shop_id:this.state.shop_id
      }
    })
    .then(function (response) {
      console.log(response.data)
      if (response.data.code===0) {
          _this.state.datalist=response.data.data
          if (response.data.data[0]) {
            _this.state.maoliShop = response.data.data[0].maoli_shop
            _this.state.rijunShop = response.data.data[0].rijun_shop
            _this.state.shunhaoShop = response.data.data[0].shunhao_shop
            // _this.state.quzong_name = response.data.data[0].quzong_name
          };

          _this.setState({})
      }else{
        alert("请求失败")
      }
    })
  }
  uniq(array){
    var temp = []; //一个新的临时数组
    for(var i = 0; i < array.length; i++){
        if(temp.indexOf(array[i]) === -1){
            temp.push(array[i]);
        }
    }
    return temp;
  }
  uniqs(okk,title){
    var result = [];
    var obj = {};
    for(var i =0; i<okk.length; i++){
        if(!obj[okk[i].title]){
        result.push(okk[i]);
        obj[okk[i].title] = true;
      }
    }
    okk=result
    return okk
  }
  getDataMsgs(data){
    if (store.getState().dataReducer.alldata.length) {
      this.state.shop_value = store.getState().dataReducer.alldata.filter(val=>val.value==data.shop_id)[0].label
    };
    // console.log(store.getState().dataReducer.alldata[0],data.shop_id)
    this.state.openApiCode = data.openApiCode
    this.state.yearID = data.year_id
    this.state.monthID = data.month_id
    // this.state.year_month = data.year_month
    this.state.shop_id = data.shop_id
    this.requistData(this)
  }
  render() {
    var alldatas = this.state.datalist
      var mmp =[]

    alldatas =[...mmp,...alldatas]

    // 拿出来一个数组创建左边的值
    var mustXiangmu =[]
    alldatas.forEach(val=>{
      mustXiangmu.push(val.xiangmu)
    })
    mustXiangmu = this.uniq(mustXiangmu)

    // 获取所有动态组件的信息
    var dynamicControl = {}
    mustXiangmu.map(val=>{
      dynamicControl[val]=[]
    })


    
    // 获取的需要展示的所有值  key值必须有,且不一样,所以要添加
    var dynamicCont = []
    alldatas.forEach((val,ind)=>{
      var dynamicList =  alldatas.filter(items=> items.xiangmu== [val.xiangmu])
      dynamicList.map((list,order)=>{
        var agg={}
        var pll ={
          title:(<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.5rem",overflow: "hidden"}}>{list.bulei_name}</p>
        </div>),
          dataIndex: list.bulei_name,
          render: renderDatas,
          width: 30,
          align: 'center',
        }
        dynamicCont.push(pll)
        agg[list.bulei_name] = list.bulei_value
        agg.omgAgg = list.bulei_name
        dynamicControl[val.xiangmu].push(agg)
      })
      var result = [];
      var obj = {};
      for(var i =0; i<dynamicControl[val.xiangmu].length; i++){
            if(!obj[dynamicControl[val.xiangmu][i].omgAgg]){
            result.push(dynamicControl[val.xiangmu][i]);
            obj[dynamicControl[val.xiangmu][i].omgAgg] = true;
          }
        }
      dynamicControl[val.xiangmu]=result
    })
    // 把获取到的动态组列 去重  
    dynamicCont = this.uniqs(dynamicCont,"title")
    const cols = [{
      title:(<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.3rem",overflow: "hidden"}}>项目</p>
        </div>),
      dataIndex: 'xiangmu',
      width: 50,
      colSpan: 2,
      fixed: 'left',
      className:"tables",
      render:(value, row, index) => {
          var obj
          if (row.font_style=="00") {
            obj = {
              children:<span>{value}</span>,
              props: {},
            }
          }else if (row.font_style=="01"){
            obj = {
              children:<span style={{paddingLeft:"0.3rem"}}>{value}</span>,
              props: {},
            }
          }else if (row.font_style=="10"){
            obj = {
              children:<span style={{fontWeight:"bolder"}}>{value}</span>,
              props: {},
            }
          }else if (row.font_style=="11"){
            obj = {
              children:<span style={{fontWeight:"bolder",paddingLeft:"0.3rem"}}>{value}</span>,
              props: {},
            }
          }else if (row.font_style<"0"){
            obj = {
              children:<span style={{color:"red"}}>{value}</span>,
              props: {},
            }
          }else{
            obj = {
              children:value,
              props: {},
            }
          }
          obj.props.colSpan=2
          return obj;
        },
      },{
      title:(<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.5rem",overflow: "hidden"}}>{this.state.shop_value}</p>
        </div>),
      dataIndex: 'quzong_value',
      render: renderDatas,
      width :30,
      align: 'center',
      },{
      title:(<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.4rem",overflow: "hidden"}}>率</p>
        </div>),
      dataIndex: 'lv',
      render: renderDatas,
      width: 30,
      align: 'center',
      },{
      title: (<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.5rem",overflow: "hidden"}}>去年同期</p>
        </div>),
      dataIndex: 'last_curr',
      render: renderDatas,
      width: 30,
      align: 'center',
      },
      ...dynamicCont,{
      title:(<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.5rem",overflow: "hidden"}}>{this.state.quzong_name}</p>
        </div>),
      dataIndex: 'quzong_value',
      render: renderDatas,
      width: 30,
      align: 'center',
      },{
      title: (<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.9rem",overflow: "hidden",textOverflow:"ellipsis",whiteSpace: "nowrap"}}>日均最高</p>
        <p style={{width:"0.9rem",overflow: "hidden",textOverflow:"ellipsis",whiteSpace: "nowrap"}}>{this.state.rijunShop}</p>
        </div>),
      dataIndex: 'rijun_max',
      render: renderDatas,
      width: 90,
      align: 'center',
      },{
      title: (<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.9rem",overflow: "hidden",textOverflow:"ellipsis",whiteSpace: "nowrap"}}>毛利率最高</p>
        <p style={{width:"0.9rem",overflow: "hidden",textOverflow:"ellipsis",whiteSpace: "nowrap"}}>{this.state.maoliShop}</p>
        </div>),
      dataIndex: 'maoli_max',
      render: renderDatas,
      width: 90,
      align: 'center',
      },{
      title: (<div style={{height:"0.45rem"}}>
        <p style={{textAlign:"center",width:"0.9rem",overflow: "hidden",textOverflow:"ellipsis",whiteSpace: "nowrap"}}>损耗率最低</p>
        <p style={{width:"0.9rem",overflow: "hidden",textOverflow:"ellipsis",whiteSpace: "nowrap"}}>{this.state.shunhaoShop}</p>
        </div>),
      dataIndex: 'shunhao_min',
      render: renderDatas,
      width: 90,
      align: 'center',
      }];
    const datas = []

    // 把所有的数据进行去重
    var result = [];
    var obj = {};
    for(var i =0; i<alldatas.length; i++){
          if(!obj[alldatas[i].xiangmu]){
          result.push(alldatas[i]);
          obj[alldatas[i].xiangmu] = true;
        }
      }
    alldatas=result
    // 把获取到动态组列的信息进行去重
    alldatas.forEach((val,ind)=>{
      dynamicControl[val.xiangmu].map(items=>{
        delete items.omgAgg
      })
      var propMsg = {}
      for(var item of dynamicControl[val.xiangmu]){
        propMsg={...item,...propMsg}
      }
      dynamicControl[val.xiangmu] = propMsg

      // 赋值给数据链
      datas.push({key:ind,...val,...dynamicControl[val.xiangmu]})
      // 更改样式
    })


    // 进行筛选
    return (
      <div className="listlive" style={{backgroundColor:"#eee"}}>
        <Row>
          <YHLiveMDApk getDataMsg={this.getDataMsgs.bind(this)}></YHLiveMDApk>
        </Row>
        <Row style={{marginTop:'0.08rem',backgroundColor:"#fff"}}>
          <Col>
            <Table 
              columns={cols} 
              rowClassName="tables2" 
              pagination={{ pageSize: 50 }} 
              scroll={{x:300}} 
              style={{fontSize:"0.12rem"}} 
              width="100%" 
              childrenColumnName="aa"
              dataSource={datas} 
              bordered />
          </Col>
        </Row>
      </div>
    );
  }
}

export default ListLive;

const renderDatas = (value, row, index) => {
    var obj
    if (row.font_style=="00") {
      obj = {
        children:<span>{value}</span>,
        props: {},
      }
    }else if (row.font_style=="01"){
      obj = {
        children:<span>{value}</span>,
        props: {},
      }
    }else if (row.font_style=="10"){
      obj = {
        children:<span style={{fontWeight:"bolder"}}>{value}</span>,
        props: {},
      }
    }else if (row.font_style=="11"){
      obj = {
        children:<span style={{fontWeight:"bolder"}}>{value}</span>,
        props: {},
      }
    }else if (parseInt(row.font_style)<0){
      console.log(value)
      obj = {
        children:<span style={{color:"red"}}>{value}</span>,
        props: {},
      }
    }else{
      obj = {
        children:value,
        props: {},
      }
    }
    return obj;
};
const data=[{
    "total_value": "1.4",
    "last_curr": "1.4",
    "quzong_value": "1.4",
    "bulei_value": "1.4",
    "lv": "-",
    "shunhao_min": "2.3",
    "font_style": "0",
    "xiangmu": "单店日均",
    "maoli_max": "2.3",
    "shop_value": "1.4",
    "rijun_max": "2.3",
    "xiangmu_id": "1",
    "bulei_name": "食品",
    "yetai_value": "1"
    }]

