import {ADD_TO_DATA} from "../actions/data-actions"
// 基础数据
const initialState ={
	alldata:[]
}
export default function(state=initialState,action){
	switch(action.type){
		case ADD_TO_DATA:{
			return {
				...state,
				alldata:[...action.payload]
			}
		}
		default:return state
	}
}