import React, { Component } from 'react';
// import store from '../store/store.js';
import { Row, Col } from 'antd';
import { Select } from 'antd';
import { Button } from 'antd';
import { Link} from "react-router-dom";

  
const Option = Select.Option;

class FirstOrder extends Component {
  constructor(){
    super();
    this.state={
      msg:"这里是app文件",
      title:"",
      makeSure:true
    } 
  }
  // 开始阶段要进行内容绘制
  componentWillMount () {

  }
  // 下拉框发生改变时触发
  handleChange(value) {
    this.setState({
      title : value
    })
  }
  handleBlockSelect(){
    if (this.state.makeSure) {
      this.state.makeSure =false
    }else{
      this.state.makeSure =true
    }
    this.setState({})
  }
  render() {
    var titleName 
    if (this.state.title =="") {
      titleName =(<Row>
          请选择你要查看的内容
        </Row>)
    }else{
      titleName =this.state.title
    }
    var isBlock
    if (this.state.makeSure) {
      isBlock =(
        <div>
          <Col span="14" offset="1">
            <Select
              showSearch
              style={{ width: "100%" }}
              placeholder="选择您要查看的表"
              optionFilterProp="children"
              onChange={this.handleChange.bind(this)}
            >
              <Option value="永辉-业态区"> 
                <Link to="/YHLiveYT">永辉生活门店一体化-业态区</Link>
              </Option>
              <Option value="永辉-门店">
                <Link to="/YHLiveMD">永辉生活门店一体化-门店</Link>
              </Option>
              <Option value="永辉-区域">
                <Link to="/YHLiveQY">永辉生活门店一体化-区域</Link>
              </Option>
              <Option value="物种-业态区">
                <Link to="/YHSuperYT">超级物种门店一体化-业态区</Link>
              </Option>
              <Option value="物种-区域">
                <Link to="/YHSuperQY">超级物种门店一体化-区域</Link>
              </Option>
              <Option value="物种-门店">
                <Link to="/YHSuperMD">超级物种门店一体化-门店</Link>
              </Option>
              <Option value="云创一体化">
                <Link to="/YCTogether">云创一体化</Link>
              </Option>
            </Select>
          </Col>
          <Col span="5" offset="1">
            <Button icon="left" onClick={this.handleBlockSelect.bind(this)}></Button>
          </Col>
          </div>
        )
    }else{isBlock =(
      <Col span="5" offset="1">
        <Button icon="right" onClick={this.handleBlockSelect.bind(this)}></Button>
      </Col>)
    }
    return (
      <div className="firstorder">
        <Row style={{marginTop:'0.1rem'}}>
            <Col offset="1" span="10">
              {titleName}
            </Col>
          </Row>
        <Row style={{marginTop:'0.1rem'}}>
            {isBlock}
        </Row>
      </div>
    );
  }
}

export default FirstOrder

