import React, { Component } from 'react';
import './Apk.css';
import { Row, Col } from 'antd';
import axios from 'axios';
import store from '../store/store.js';
// 引入 ant design
import { Select } from 'antd';
import { Button } from 'antd';
import {addToData} from "../store/actions/data-actions"


const Option = Select.Option;
// 引入路由跳转
class App extends Component {
  constructor(){
    super();
    this.state={
      msg:"超级物种-业态区",
      
      openApiCode:"OPENAPI_000332",
      shopId:"",
      shopIds:[],

      year_month:"2018-11",
      // --------------------------删除点1
      date:"2018年11月",
      dates:[],
    } 
  }
  // 开始阶段要进行内容绘制
  componentWillMount(){
    this.CurentTime()

    //  ----------------------------删除点1
    var theDate = this.state.date
    var dateN = theDate.split("年").join("-").split("月").join("").split("-")
    var data={
      openApiCode:this.state.openApiCode,

      year_id:dateN[0],
      month_id:dateN[1],
      // year_month:this.state.year_month,
      shop_id:this.state.shopId
    }
    this.props.getDataMsg(data)

    this.request(this)

  }
  // 请求门店信息
  request(_this){
    var response = [
        {"label":"9D01国顺东路店","value":"9D01","active":0},
        {"label":"9D13国顺路","value":"9D13","active":0}
    ]
    // 做数据存储
    // store.dispatch(addToData(response));

    // 开始请求
    axios.get('http://192.168.21.197:11550/finance/filter/values')
    .then(function (response) {
      alert("请求成功")
      console.log(response)
      if (response.data.code===0) {
          if (response.data.filter_name&&response.data.filter_name=="业态总") {
            store.dispatch(addToData(response.data.data));
            _this.state.shopIds=response.data.data
          }else{
            store.dispatch(addToData({"label":"你没有查看的权限,请刷新","value":"0","active":0}));
            _this.state.shopIds=""
          }
          _this.setState({})
      }else{
        alert("请求失败")
        store.dispatch(addToData({"label":"你没有查看的权限,请刷新","value":"0","active":0}));
        _this.state.shopIds=""
        _this.setState({})
      }
    }).catch(function(msg){
      alert("请求失败")
      store.dispatch(addToData([{"label":"你没有查看的权限,请刷新","value":"0","active":0}]));
        _this.state.shopIds=""
        _this.setState({})
    })
  }
  // 获取区域
  handleChange(value) {
    this.setState({
      shopId:value
    })
    // -------------------------删除点1
    var theDate = this.state.date
    var dateN = theDate.split("年").join("-").split("月").join("").split("-")
    var data={
      openApiCode:this.state.openApiCode,

      year_id:dateN[0],
      month_id:dateN[1],
      // year_month:this.state.year_month,

      shop_id:value
    }
    this.props.getDataMsg(data)
  }
  // 获取时间
  handDataChange(value,ind){
    this.setState({
      date : value
    })


    // -------------------------删除点1
    var dateN = value.split("年").join("-").split("月").join("").split("-")
    // var dateY = value.split("年").join("-").split("月")[0]
    var data={
      openApiCode:this.state.openApiCode,

      year_id:dateN[0],
      month_id:dateN[1],
      // year_month:dateY,

      shop_id:this.state.shopId
    }
    

    this.props.getDataMsg(data)
  }
  // 获取最近十个月的时间
  CurentTime(){ 
      var now = new Date();
      var year = now.getFullYear();       //年
      var month = now.getMonth() + 1;     //月
      var date1 = year +"年" + month+"月"
      this.state.dates.push(date1)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date2 = year +"年" + month+"月"
      this.state.dates.push(date2)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date3 = year +"年" + month+"月"
      this.state.dates.push(date3)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date4 = year +"年" + month+"月"
      this.state.dates.push(date4)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date5 = year +"年" + month+"月"
      this.state.dates.push(date5)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date6 = year +"年" + month+"月"
      this.state.dates.push(date6)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date7 = year +"年" + month+"月"
      this.state.dates.push(date7)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date8 = year +"年" + month+"月"
      this.state.dates.push(date8)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date9 = year +"年" + month+"月"
      this.state.dates.push(date9)
      month-=1
      if (month<=0) {
        month=12
        year-=1
      };
      var date10 = year +"年" + month+"月"
      this.state.dates.push(date10)
      this.setState({})

  } 
  // 点击月
  monthClick(){
    var now = new Date();
    var year = now.getFullYear();       //年
    var month = now.getMonth() + 1; 
    var value = year+"-"+month
    this.setState({
      year_month:value
    })
    var data={
      openApiCode:this.state.openApiCode,
      year_month:value,
      shop_id:this.state.shopId
    }
    // this.props.getDataMsg(data)
  }
  // 点击年
  yearClick(){
      var now = new Date();
      var year = now.getFullYear();       //年
      var value = year+"-"+1
      var value2 = year+"-"+12
      this.setState({
        year_month:value
      })
      var data={
        openApiCode:this.state.openApiCode,
        year_month:value,
        shop_id:this.state.shopId
      }
      // this.props.getDataMsg(data)
  }

  render() {
    // 日期选择
    var region
    var daty
    if (this.state.dates.length) {
      daty=this.state.dates.map((val,ind)=>{
        return (
        <Option value={val} key={ind}>
          {val}
        </Option>
        )
      })
    };
    // 区域选择
     if (this.state.shopIds.length) {
      region = this.state.shopIds.map((val,ind)=>{
      return (
        <Option value={val.value} key={ind}>
            {val.label}
        </Option>
      )
    })
    }
    return (
      <div className="App" style={{backgroundColor:"#eee"}}>
        <Row style={{backgroundColor:"#fff",paddingTop:"0.05rem",paddingBottom:"0.05rem"}}>
          <Col span="19" offset="1" style={{textAlign:"left",fontSize:"0.14rem",fontWeight:600}}>
          {this.state.msg}
          </Col>
        </Row>
        <Row style={{marginTop:'0.1rem',backgroundColor:"#fff",paddingTop:"0.05rem",paddingBottom:"0.05rem"}}>
          <Col span="2" offset="1" style={{textAlign:"left",fontSize:"0.13rem",lineHeight:"0.25rem"}}>月份</Col>
          <Col span="7" style={{marginLeft:"0.05rem"}}>
            <Select
              showSearch
              value={this.state.year_month}
              style={{ width: "100%"}}
              placeholder="请选择时间轴"
              optionFilterProp="children"
              onChange={this.handDataChange.bind(this)}
              filterOption={(input, option) => option.props.children.toLowerCase().indexOf(input.toLowerCase()) >= 0}
            >
              {daty}
            </Select>
          </Col>
          <Col span="2" offset="1" style={{textAlign:"left",fontSize:"0.14rem",lineHeight:"0.25rem"}}>门店</Col>
          <Col span="7" style={{marginLeft:"0.05rem"}}>
            <Select
              showSearch
              value={this.state.shopId}
              style={{ width: "100%" }}
              placeholder="请选择区域范围"
              optionFilterProp="children"
              onChange={this.handleChange.bind(this)}
              filterOption={(input, option) => option.props.children.toLowerCase().indexOf(input.toLowerCase()) >= 0}
            >
              {region}
            </Select>
          </Col>
        </Row>
        <Row style={{marginTop:'0.1rem',backgroundColor:"#fff",paddingTop:"0.05rem",paddingBottom:"0.05rem"}}>
          <Col span="4" offset="1">
            <Button onClick={this.monthClick.bind(this)}>当月</Button>
          </Col>
          <Col span="4" offset="1">
            <Button onClick={this.yearClick.bind(this)}>年累计</Button>
          </Col>
        </Row>
      </div>
    );
  }
}

export default App;

