import axios from 'axios'
import { suffix } from './utils'
import _ from "lodash/object";


class Api {

  // get请求
  static get = (url, params, option) => {
    let newParmas = _.assign({}, params);
    let signedObj = suffix(newParmas);
    newParmas = _.assign(signedObj,params);
    const paramsString = Api._jsonToQueryString(url, newParmas)
    let api =`${url}${paramsString}`
    
    return new Promise((resolve, reject) => {
      axios.get(api, params )
      .then(function (response) {
        Api.toastfilterError(response)
        resolve(response.data)
      }).catch(function (error) {
        console.log(error)
        if (error.toString() === 'Error: Request failed with status code 404') {
          alert('网络异常，请重试！')
        }
        resolve({})
      })
    })
  }


  static post = (url, params) => {
    params = params || {}
    let newParmas = {};
    newParmas.json = JSON.stringify(params);
    let signedObj = suffix(newParmas);
    const paramsString = Api._jsonToQueryString(signedObj);
    const api = `${url}${paramsString}`;
    return new Promise((resolve, reject) => {
      axios.post(api,
        params
      ).then(function (response) {
        Api.toastfilterError(response)
        resolve(response.data)
      }).catch(function (error) {
        Api.printError(api, params, error)
        console.log(error)
        if (error.toString() === 'Error: Request failed with status code 404') {
          alert('网络异常，请重试！')
        }
        // 网络错误，默认返回一个空Object
        resolve({})
      })
    })
  }


  static _jsonToQueryString = (url, json) => {
      let join = ''
      url.includes('?') ? join = `&` : join = `?`
      return join +
          Object.keys(json).map(function (key) {
              return encodeURIComponent(key) + '=' + (json[key]);
          }).join('&');
  }


  // 处理异常
  static toastfilterError = (response) => {
    const code = response.data.code
    if(code){
      if ([1, 500, -98].includes(code)) {
          alert( response.data.msg ? response.data.msg : '请求失败，请重试！' )
      }
      if ([-99].includes(code)) {
          alert( response.data.msg ? response.data.msg : '未登录，请登录！' )
      }
    }
  }

}

export default Api
