import React, { Component } from 'react';

import { HashRouter as Router, Route } from "react-router-dom";

import ListOne from '../components/aaa'

import ListLive from '../computers/listLive';
import YHLiveMD from '../YHLiveMD/YHLiveMD';
import YHLiveYT from '../YHLiveYT/YHLiveYT';
import YHLiveQY from '../YHLiveQY/YHLiveQY';
import YHSuperQY from '../YHSuperQY/YHSuperQY';
import YHSuperMD from '../YHSuperMD/YHSuperMD';
import YHSuperYT from '../YHSuperYT/YHSuperYT';
import YCTogether from '../YCTogether/YCTogether';

import App from '../App';

class Rent extends Component {
  render() {
    return (
      <Router>
        <div>
          <Route path="/App" component={App} />
          <Route path="/ListOne" component={ListOne}/>
          <Route path="/ListLive" component={ListLive}/>
          <Route path="/YHLiveMD" component={YHLiveMD}/>
          <Route path="/YHLiveYT" component={YHLiveYT}/>
          <Route path="/YHLiveQY" component={YHLiveQY}/>
          <Route path="/YHSuperQY" component={YHSuperQY}/>
          <Route path="/YHSuperMD" component={YHSuperMD}/>
          <Route path="/YHSuperYT" component={YHSuperYT}/>
          <Route path="/YCTogether" component={YCTogether}/>
        </div>
      </Router>
    );
  }
}

export default Rent