import React, { Component } from 'react';
// import store from '../store/store.js';
// 引入 ant design
import { Table } from 'antd';
// 引入路由跳转
import api from '../utils/api/';
function row2col(jsonData, idField, colField, valueField, emptyValue) {
  var result = [], //存储返回的数据
    idIndexData = {}, //存储id在数组中的信息(位置)
    resultColumns = {}, //存储列名数据
    curRecord = null; //存储当前数据

  var colFields = colField.split(','); //

  // 循环整个JSON数组：[{...},{...},{...},...]
  for (var idx = 0; idx < jsonData.length; idx++) {

    //当前json数据对象
    var cdata = jsonData[idx];

    //根据主键值，查找到结果数组中的索引号
    var idValue = cdata[idField];
    var num = idIndexData[idValue]; //获取存储该id的数组索引号
    if (num != null) {
      curRecord = result[num];
    } else {
      //初始化数据时保持完整的结构信息 避免因为缺乏数据，缺乏指定的列数据
      curRecord = {};
    }

    // 指定的colFields列下的数据作为y轴，则取出该列的数据作为y轴即可
    for (var i in colFields) {
      var key = colFields[i];

      //获取到colField的值，作为列名
      var value = cdata[valueField];
      curRecord[value] = cdata[key];

      //存储列名
      resultColumns[value] = null;
      break;
    }

    //除数据内容外，还需要添加主键数据
    curRecord[idField] = idValue;

    //对象若为新建 则新增进数组
    if (num == null) {
      idIndexData[idValue] = result.push(curRecord) - 1;
    }
  }

  //数据检查 由于是将行数据作为列名，则可能会存在部分行缺少其他列数据，若缺少，则指定默认值
  for (var i in result) {
    for (var name in resultColumns) {
      if (!result[i].hasOwnProperty(name)) result[i][name] = emptyValue;
    }
  }
  return result;
}
const renderDatas = (value, k) => {
  console.log(value,k)
  const obj = {
    children: <span>{+value < 0 ? 'asdf' : value}</span>,
    props: {},
  }
  return obj;
};
const cols = [{
    title: '项目',
    dataIndex: 'xiangmu',
    render: renderDatas
  }, {
    title: '田林路',
    dataIndex: 'quzong_value',
    render: renderDatas
  }, {
    title: '率',
    dataIndex: 'lv',
    render: renderDatas
  }, {
    title: '去年同期',
    dataIndex: 'last_curr',
    render: renderDatas
  }, {
    title: '食品',
    dataIndex: 'bulei_value',
    render: renderDatas
  }, {
    title: '日均最高',
    dataIndex: 'rijun_max',
    render: renderDatas
  }, {
    title: '毛利率最高',
    dataIndex: 'maoli_max',
    render: renderDatas
  }, {
    title: '损耗率最低',
    dataIndex: 'shunhao_min',
    render: renderDatas
  }, ]

class ListOne extends Component {
  constructor(){
    super();
    this.state={
      msg:"这里是ListLive文件",
      datalist:[],
      header: [],
      resultData: {},
      columns: cols
    } 
  }
  // 开始阶段要进行内容绘制
  componentWillMount () {
    const { columns } = this.state

    api.get('http://yc-bi-api.yonghuivip.com/portal-api/openApi/portal/report?openApiCode=OPENAPI_000332&year_id=2018&month_id=11&shop_id=9D13').then(res => {
      if (+res.code === 0) {
        let cc = [{
          "total_value": "1.4",
          "last_curr": "1.4",
          "quzong_value": "1.4",
          "bulei_value": "-1.1114",
          "lv": "-",
          "shunhao_min": "2.3",
          "font_style": "0",
          "xiangmu": "aaa日均",
          "maoli_max": "2.3",
          "shop_value": "1.4",
          "rijun_max": "2.3",
          "xiangmu_id": "-1",
          "bulei_name": "酒水",
          "yetai_value": "-1"
        }]
        let fiterdata = []
        let yy = res.data.slice(0, 5)
        yy.splice(2, 0, ...cc)
        let b = []
        yy.map(res=>{
          let h = {
            bulei_name: res.bulei_name,
            bulei_value: res.bulei_value,
            xiangmu: res.xiangmu
          }
          b.push(h)
        })
        var colField = 'bulei_value', valueField = 'bulei_name', idField = 'xiangmu';
        const resultData = row2col(b, idField, colField, valueField, '-')
        
        yy.map((val, j) => {
          let list = resultData[j]
          fiterdata.push({ ...list, ...val })
        })
        this.state.datalist = yy
        // columns.splice(2, 0, ...resultData)
        this.setState({})
      }
    })
  }
  render() {
    const { columns } = this.state

    const datas = []
    this.state.datalist.map((val,ind)=>{
      datas.push({'key':ind, ...val})
    })
    return (
      <div className="ListOne">
        <Table className="tablelist" columns={columns} dataSource={datas} pagination={false} bordered />
      </div>
    );
  }
}
export default ListOne

